#include<bits/stdc++.h>
#define ll long long
using namespace std;
template<typename tn> void read(tn &a){
	tn x=0,f=1; char c=' ';
	for(;!isdigit(c);c=getchar()) if(c=='-') f=-1;
	for(;isdigit(c);c=getchar()) x=x*10+c-'0';
	a=x*f;
}
int n;
char mp[45][45];
ll f[45][45][45],fs[45][45][45];
int main(){
	read(n);
	for(int i=1;i<=2*n;i++){
		cin>>mp[i]+1;
		f[i][i][i]=1;
		for(int j=i+1;j<=2*n;j++)
			fs[i][j][i]=mp[i][j]=='1';
	}
	n*=2;
	for(int len=3;len<=n;len++){
		for(int l=1;l<=n-len+1;l++){
			int r=l+len-1;
			for(int p=l;p<r;p++)
				for(int q=l+1;q<=r;q++){
					ll now=0;
					for(int k=q;k<=r;k++) now+=f[q][k][r]*fs[l][k][p];
					for(int mid=l+1;mid<r;mid++) f[l][mid][r]+=now*f[p+1][mid][q-1];
				}
			for(int mid1=l+1;mid1<r;mid1++)
				for(int mid2=r+1;mid2<=n;mid2++)
					if(mp[mid1][mid2]=='1')
						fs[l][mid2][r]+=f[l][mid1][r];
		}
	}
	ll ans=0;
	for(int i=2;i<=n;i++)
		if(mp[1][i]=='1') ans+=f[2][i][n];
	cout<<ans<<'\n';
	return 0;
}

```

